import React, { useState, useEffect } from 'react';
import axios from 'axios';

const StockMovementForm = ({ refreshMovements, refreshProducts, updateProductQuantity }) => {
    const [products, setProducts] = useState([]); // Estado para produtos
    const [movement, setMovement] = useState({
        produto: '', // ID do produto
        tipo_movimentacao: 'entrada',
        quantidade: '',
        motivo: ''
    });

    // Busca produtos ao montar o componente
    useEffect(() => {
        const fetchProducts = async () => {
            try {
                const response = await axios.get('http://127.0.0.1:8000/api/produtos/');
                setProducts(response.data);
            } catch (error) {
                console.error("Erro ao buscar produtos:", error);
            }
        };

        fetchProducts();
    }, []);

    // Função para lidar com mudanças nos inputs
    const handleChange = (e) => {
        const { name, value } = e.target;
        setMovement({ ...movement, [name]: value });
    };

    // Função para enviar a movimentação
    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            // Registra a movimentação na API
            await axios.post('http://127.0.0.1:8000/api/movimentacoes/', {
                produto: movement.produto,
                tipo_movimentacao: movement.tipo_movimentacao,
                quantidade: parseInt(movement.quantidade, 10),
                motivo: movement.motivo
            });

            // Atualiza a quantidade do produto
            await updateProductQuantity(movement.produto, movement.tipo_movimentacao, parseInt(movement.quantidade, 10));

            // Atualiza as movimentações e produtos após o envio
            refreshMovements(); // Recarrega a lista de movimentações
            refreshProducts(); // Recarrega a lista de produtos

            // Reseta o formulário
            setMovement({ produto: '', tipo_movimentacao: 'entrada', quantidade: '', motivo: '' });

        } catch (error) {
            console.error("Erro ao registrar movimentação:", error);
            alert("Erro ao registrar movimentação: " + (error.response ? error.response.data : error.message));
        }
    };

    return (
        <div>
            <form onSubmit={handleSubmit}>
                <select name="produto" value={movement.produto} onChange={handleChange} required>
                    <option value="">Selecione um Produto</option>
                    {products.map((product) => (
                        <option key={product.id} value={product.id}>
                            {product.nome}
                        </option>
                    ))}
                </select>

                <select name="tipo_movimentacao" value={movement.tipo_movimentacao} onChange={handleChange}>
                    <option value="entrada">Entrada</option>
                    <option value="saida">Saída</option>
                </select>

                <input
                    type="number"
                    name="quantidade"
                    value={movement.quantidade}
                    onChange={handleChange}
                    placeholder="Quantidade"
                    required
                />
                <input
                    type="text"
                    name="motivo"
                    value={movement.motivo}
                    onChange={handleChange}
                    placeholder="Motivo"
                />

                <button type="submit">Registrar</button>
            </form>
        </div>
    );
};

export default StockMovementForm;
